router.get("/api/ai-interactions/:id", async (event, user) => {
  requireAdmin(user);
  const id = event.pathParameters.id;
  if (!isValidUUID(id)) return error(400, { error: "id no es un UUID v\xE1lido" });
  const { rows } = await db.query("SELECT * FROM ai_interactions WHERE id=$1", [id]);
  if (!rows.length) return error(404, { error: "Interacci\xF3n no encontrada" });
  return ok(rows[0]);
});
router.post("/api/ai-interactions/:id/decision", async (event, user) => {
  const id = event.pathParameters.id;
  if (!isValidUUID(id)) return error(400, { error: "id no es un UUID v\xE1lido" });
  const body = JSON.parse(event.body || "{}");
  const decision = String(body.decision || "").trim();
  const feedback = body.feedback || null;
  if (!AI_VALID_DECISIONS.includes(decision)) {
    return error(400, { error: `decision inv\xE1lida (${AI_VALID_DECISIONS.join("|")})` });
  }
  const { rows } = await db.query(
    "SELECT user_id, human_decision FROM ai_interactions WHERE id=$1",
    [id]
  );
  if (!rows.length) return error(404, { error: "Interacci\xF3n no encontrada" });
  const isAdmin = user.role === "admin" || user.role === "superadmin";
  if (!isAdmin && rows[0].user_id !== user.id) {
    return error(403, { error: "No puedes modificar la decisi\xF3n de otra interacci\xF3n" });
  }
  if (rows[0].human_decision) {
    return error(409, {
      error: `Esta interacci\xF3n ya tiene decisi\xF3n registrada (${rows[0].human_decision}).`,
      code: "already_decided"
    });
  }
  const { rows: updated } = await db.query(
    `UPDATE ai_interactions
        SET human_decision = $2,
            human_feedback = $3,
            decided_at     = NOW()
      WHERE id = $1
      RETURNING id, human_decision`,
    [id, decision, feedback]
  );
  return ok(updated[0]);
});
